// ============================================
// NODE 2: Parse CSV Email Performance Data
// ============================================
// Expects CSV data as base64 in body.csv_data
// or as raw text in body.csv_text
// or as a file upload in binary data

let csvText = '';

// Try multiple input methods
const input = $input.first();

if (input.binary && input.binary.file) {
  // File upload via webhook
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'file');
  csvText = buffer.toString('utf-8');
} else if (input.json.csv_data) {
  // Base64 encoded
  csvText = Buffer.from(input.json.csv_data, 'base64').toString('utf-8');
} else if (input.json.csv_text) {
  // Raw text
  csvText = input.json.csv_text;
} else {
  // Use sample data for testing
  csvText = `Email Name,Subject Line,Send Date,Status,Recipients,Delivered,Delivered %,Open Rate,Click Rate,Click-through Rate,Bounces,Bounce %,Unsubscribes,Unsubscribe %
Welcome Series - Email 1,Welcome to Our Community!,2025-12-01,Sent,150,145,96.7%,28.3%,4.1%,14.5%,5,3.3%,1,0.7%
Monthly Newsletter - Jan,January Insights,2026-01-15,Sent,140,137,97.9%,22.1%,2.8%,12.7%,3,2.1%,2,1.4%
Product Update,New Feature: Analytics Dashboard,2026-01-22,Sent,138,136,98.6%,31.5%,5.2%,16.5%,2,1.4%,0,0.0%
Monthly Newsletter - Feb,February Insights,2026-02-01,Sent,134,131,97.8%,19.8%,1.9%,9.6%,3,2.2%,1,0.7%
Re-engagement,We miss you! Special offer inside,2026-02-08,Sent,25,24,96.0%,16.0%,8.0%,50.0%,1,4.0%,0,0.0%`;
}

// Parse CSV
const lines = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim());

const emails = lines.slice(1).map(line => {
  // Handle commas inside quoted fields
  const values = line.match(/("[^"]*"|[^,]+)/g) || [];
  const row = {};
  headers.forEach((header, i) => {
    let val = (values[i] || '').trim().replace(/^"|"$/g, '');
    row[header] = val;
  });
  return row;
}).filter(row => row['Email Name']); // Skip empty rows

// Calculate aggregate metrics
const totalSent = emails.reduce((sum, e) => sum + parseInt(e['Recipients'] || 0), 0);
const totalDelivered = emails.reduce((sum, e) => sum + parseInt(e['Delivered'] || 0), 0);
const avgOpenRate = emails.reduce((sum, e) => sum + parseFloat(e['Open Rate'] || 0), 0) / emails.length;
const avgClickRate = emails.reduce((sum, e) => sum + parseFloat(e['Click Rate'] || 0), 0) / emails.length;
const totalBounces = emails.reduce((sum, e) => sum + parseInt(e['Bounces'] || 0), 0);
const totalUnsubs = emails.reduce((sum, e) => sum + parseInt(e['Unsubscribes'] || 0), 0);

return [{
  json: {
    emailPerformance: {
      emails: emails,
      aggregates: {
        totalEmails: emails.length,
        totalSent,
        totalDelivered,
        deliveryRate: ((totalDelivered / totalSent) * 100).toFixed(1),
        avgOpenRate: avgOpenRate.toFixed(1),
        avgClickRate: avgClickRate.toFixed(1),
        totalBounces,
        totalUnsubs,
        bounceRate: ((totalBounces / totalSent) * 100).toFixed(1),
        unsubRate: ((totalUnsubs / totalSent) * 100).toFixed(1)
      }
    },
    slackChannel: input.json.channel_id || null
  }
}];

// ============================================
// NODE 6: Assemble Analysis Payload
// ============================================
// Combines CSV data + HubSpot API data into
// a structured payload for Claude analysis

const csvNode = $('Parse CSV Data').first().json;
const contactsData = $('HubSpot: Get Contacts').first().json;
const dealsData = $('HubSpot: Get Deals').first().json;
const listsData = { results: [
  { properties: { hs_list_name: 'All customers', hs_list_size: '0' }},
  { properties: { hs_list_name: 'Newsletter subscribers', hs_list_size: '0' }},
  { properties: { hs_list_name: 'Unsubscribed', hs_list_size: '0' }}
]};

const contacts = contactsData.results || [];
const deals = dealsData.results || [];
const lists = listsData.results || [];

// ---- CRM METRICS ----

// Lifecycle distribution
const lifecycleDistribution = {};
contacts.forEach(c => {
  const stage = c.properties?.lifecyclestage || 'unknown';
  lifecycleDistribution[stage] = (lifecycleDistribution[stage] || 0) + 1;
});

// Lead status distribution
const leadStatusDistribution = {};
contacts.forEach(c => {
  const status = c.properties?.hs_lead_status || 'none';
  leadStatusDistribution[status] = (leadStatusDistribution[status] || 0) + 1;
});

// Engagement health
const withEmailActivity = contacts.filter(c => 
  parseInt(c.properties?.hs_email_delivered || 0) > 0
).length;

const optedOut = contacts.filter(c => 
  c.properties?.hs_email_optout === 'true'
).length;

const disengaged = contacts.filter(c => 
  parseInt(c.properties?.hs_email_sends_since_last_engagement || 0) > 5
).length;

const highEngagement = contacts.filter(c => {
  const opens = parseInt(c.properties?.hs_email_open || 0);
  const clicks = parseInt(c.properties?.hs_email_click || 0);
  return opens > 3 || clicks > 1;
}).length;

// Deal metrics
const dealStages = {};
deals.forEach(d => {
  const stage = d.properties?.dealstage || 'unknown';
  dealStages[stage] = (dealStages[stage] || 0) + 1;
});

const totalRevenue = deals.reduce((sum, d) => 
  sum + parseFloat(d.properties?.amount || 0), 0
);

const closedWonDeals = deals.filter(d => 
  d.properties?.dealstage === 'closedwon'
);

// List/segment info
const segments = lists.map(l => ({
  name: l.properties?.hs_list_name || 'Unnamed',
  size: parseInt(l.properties?.hs_list_size || 0),
  type: l.properties?.hs_list_type || 'unknown'
}));

// ---- ASSEMBLE PAYLOAD ----

const analysisPayload = {
  emailPerformance: csvNode.emailPerformance,

  crmMetrics: {
    contacts: {
      total: contacts.length,
      lifecycleDistribution,
      leadStatusDistribution
    },
    engagement: {
      withEmailActivity,
      withoutEmailActivity: contacts.length - withEmailActivity,
      optedOut,
      disengaged,
      highEngagement,
      engagementRate: ((withEmailActivity / contacts.length) * 100).toFixed(1) + '%'
    },
    deals: {
      total: deals.length,
      totalRevenue,
      closedWon: closedWonDeals.length,
      avgDealSize: deals.length > 0 ? (totalRevenue / deals.length).toFixed(0) : 0,
      stageDistribution: dealStages
    },
    segments: {
      total: segments.length,
      lists: segments,
      totalSegmentedContacts: segments.reduce((sum, s) => sum + s.size, 0)
    }
  },

  metadata: {
    auditDate: new Date().toISOString(),
    portalId: '243444428',
    tier: 'Marketing Hub Starter',
    dataSource: 'Hybrid (API + CSV export)'
  }
};

return [{
  json: {
    analysisPayload,
    slackChannel: csvNode.slackChannel
  }
}];

// ============================================================
// FORMAT: Simple Slack Message + Report Data
// ============================================================
// UPDATED: Adds scriptInputBase64 for Execute Command node
// ============================================================

var claudeResponse = $input.first().json;
var payloadNode = $('Assemble Analysis Payload').first().json;

// Extract text from Claude response
var analysisText = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  analysisText = claudeResponse.content[0].text;
}

// Parse JSON with character-by-character state machine
var analysis;
try {
  var cleaned = analysisText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  var inString = false;
  var escaped = false;
  var fixed = '';
  for (var i = 0; i < cleaned.length; i++) {
    var ch = cleaned[i];
    if (escaped) { fixed += ch; escaped = false; continue; }
    if (ch === '\\' && inString) { fixed += ch; escaped = true; continue; }
    if (ch === '"') { inString = !inString; fixed += ch; continue; }
    if (inString && ch === '\n') { fixed += '\\n'; continue; }
    if (inString && ch === '\r') { fixed += '\\r'; continue; }
    if (inString && ch === '\t') { fixed += '\\t'; continue; }
    fixed += ch;
  }

  analysis = JSON.parse(fixed);
} catch (e) {
  analysis = {
    overallScore: 'ERR',
    executiveSummary: 'Failed to parse Claude analysis: ' + e.message,
    recommendations: []
  };
}

// ---- BUILD SIMPLE MRKDWN MESSAGE ----

var scoreEmoji = {
  'A+': '\uD83C\uDFC6', 'A': '\uD83C\uDF1F', 'A-': '\u2B50',
  'B+': '\u2705', 'B': '\uD83D\uDC4D', 'B-': '\uD83D\uDC4C',
  'C+': '\u26A0\uFE0F', 'C': '\uD83D\uDE10', 'C-': '\uD83D\uDC4E',
  'D+': '\uD83D\uDEA8', 'D': '\uD83D\uDEA8', 'F': '\uD83D\uDD25'
};
var emoji = scoreEmoji[analysis.overallScore] || '\uD83D\uDCCA';

var lines = [];

lines.push(emoji + ' *Campaign Audit Complete \u2014 Score: ' + analysis.overallScore + '*');
lines.push('');
lines.push(analysis.executiveSummary || 'Analysis complete.');
lines.push('');

if (analysis.benchmarkComparison) {
  var bc = analysis.benchmarkComparison;
  var benchParts = [];
  if (bc.openRate) {
    var oArrow = bc.openRate.verdict === 'above' ? '\u2191' : '\u2193';
    benchParts.push('Open: ' + bc.openRate.yours + '% ' + oArrow + ' (ind: ' + bc.openRate.industry + '%)');
  }
  if (bc.clickRate) {
    var cArrow = bc.clickRate.verdict === 'above' ? '\u2191' : '\u2193';
    benchParts.push('Click: ' + bc.clickRate.yours + '% ' + cArrow + ' (ind: ' + bc.clickRate.industry + '%)');
  }
  if (benchParts.length) {
    lines.push('\uD83D\uDCC8 *Benchmarks:* ' + benchParts.join('  \u2022  '));
    lines.push('');
  }
}

if (analysis.emailAnalysis) {
  var ea = analysis.emailAnalysis;
  lines.push('\uD83D\uDCE7 *Email Performance: ' + (ea.overallRating || 'N/A') + '*');
  lines.push('Best: *' + (ea.topPerformer || 'N/A') + '*  |  Needs work: *' + (ea.bottomPerformer || 'N/A') + '*');
  lines.push('');
}

if (analysis.audienceHealth) {
  var ah = analysis.audienceHealth;
  lines.push('\uD83D\uDC65 *Audience Health: ' + (ah.score || 'N/A') + '*');
  lines.push((ah.totalContacts || 0) + ' contacts  |  ' + (ah.activeRate || 0) + '% active  |  ' + (ah.disengagedRate || 0) + '% disengaged');
  if (ah.risks && ah.risks.length > 0) {
    lines.push('\u26A0\uFE0F Risk: ' + ah.risks[0]);
  }
  lines.push('');
}

if (analysis.recommendations && analysis.recommendations.length > 0) {
  lines.push('\uD83C\uDFAF *Top Recommendations:*');
  var maxRecs = Math.min(analysis.recommendations.length, 3);
  for (var ri = 0; ri < maxRecs; ri++) {
    var r = analysis.recommendations[ri];
    var icon = r.priority === 'high' ? '\uD83D\uDD34' : r.priority === 'medium' ? '\uD83D\uDFE1' : '\uD83D\uDFE2';
    lines.push(icon + ' ' + (ri + 1) + '. *' + r.title + '* \u2014 _' + (r.expectedImpact || '') + '_');
  }
  lines.push('');
}

var dateStr = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
var pId = (payloadNode.analysisPayload && payloadNode.analysisPayload.metadata && payloadNode.analysisPayload.metadata.portalId) ? payloadNode.analysisPayload.metadata.portalId : 'N/A';
lines.push('_Campaign Auditor v1  \u2022  ' + dateStr + '  \u2022  Portal: ' + pId + '_');

var slackMessage = lines.join('\n');

// ---- BASE64 ENCODE SCRIPT INPUT ----
// This lets the Execute Command node pipe data to the DOCX script
// without any Code node needing require('fs')

var scriptPayload = JSON.stringify({
  analysis: analysis,
  metadata: {
    portalId: pId,
    tier: (payloadNode.analysisPayload && payloadNode.analysisPayload.metadata && payloadNode.analysisPayload.metadata.tier) ? payloadNode.analysisPayload.metadata.tier : 'HubSpot',
    dataSource: (payloadNode.analysisPayload && payloadNode.analysisPayload.metadata && payloadNode.analysisPayload.metadata.dataSource) ? payloadNode.analysisPayload.metadata.dataSource : 'API + CSV'
  }
});
var scriptInputBase64 = Buffer.from(scriptPayload).toString('base64');

return [{
  json: {
    slackMessage: slackMessage,
    analysis: analysis,
    rawResponse: analysisText,
    payload: payloadNode.analysisPayload,
    scriptInputBase64: scriptInputBase64
  }
}];

const payload = $('Assemble Analysis Payload').first().json;

const systemPrompt = `You are a senior marketing strategist and HubSpot campaign auditor. You analyze email campaign performance data alongside CRM health metrics to produce actionable audit reports.

Your analysis framework:

1. EMAIL PERFORMANCE SCORING
   - Compare each email's metrics against industry benchmarks
   - Industry avg: Open Rate 21.5%, Click Rate 2.3%, Bounce <2%, Unsub <0.5%
   - Score each email: A (exceptional), B (good), C (below avg), D (problem)
   - Identify patterns: declining engagement, subject line effectiveness, timing

2. AUDIENCE HEALTH ASSESSMENT
   - Contact database completeness and quality
   - Engagement distribution (active/passive/disengaged/opted-out)
   - List hygiene score
   - Segmentation maturity

3. LIFECYCLE FUNNEL ANALYSIS
   - Stage distribution vs healthy funnel benchmarks
   - Conversion velocity indicators
   - Revenue pipeline alignment
   - Funnel gaps

4. STRATEGIC RECOMMENDATIONS
   - Prioritize by impact (high/medium/low) and effort (quick_win/project/initiative)
   - Be specific with numbers from the data
   - Reference actual data points
   - Include what NOT to do

RESPOND ONLY WITH VALID JSON. No markdown, no code fences, just JSON.

CRITICAL: Keep your JSON response under 3000 tokens. Be concise in insights - one sentence each. Limit emails array to top 5 and bottom 2 performers only. Maximum 4 recommendations.

JSON Structure:
{
  "overallScore": "B+",
  "executiveSummary": "2-3 sentence overview",
  "emailAnalysis": {
    "overallRating": "B",
    "emails": [{"name":"...","score":"A","openRate":25.0,"clickRate":3.0,"insight":"One sentence"}],
    "patterns": ["pattern 1"],
    "topPerformer": "email name",
    "bottomPerformer": "email name"
  },
  "audienceHealth": {
    "score": "C+",
    "totalContacts": 32,
    "activeRate": 45.0,
    "disengagedRate": 20.0,
    "optOutRate": 5.0,
    "findings": ["finding 1"],
    "risks": ["risk 1"]
  },
  "funnelAnalysis": {
    "score": "B-",
    "distribution": {"lead": 15, "mql": 5},
    "findings": ["finding 1"],
    "gaps": ["gap 1"]
  },
  "recommendations": [{
    "priority": "high",
    "effort": "quick_win",
    "title": "Short title",
    "description": "Detailed recommendation",
    "expectedImpact": "What improvement to expect"
  }],
  "benchmarkComparison": {
    "openRate": {"yours": 22.0, "industry": 21.5, "verdict": "above"},
    "clickRate": {"yours": 1.8, "industry": 2.3, "verdict": "below"}
  }
}`;

const userMessage = `Analyze this HubSpot campaign data and provide your audit:

## Email Campaign Performance (CSV Export)
${JSON.stringify(payload.analysisPayload.emailPerformance.aggregates)}

Individual emails:
${payload.analysisPayload.emailPerformance.emails.map(e => `${e['Email Name']}: Open ${e['Open Rate']}, Click ${e['Click Rate']}, Bounce ${e['Bounce %']}, Unsub ${e['Unsubscribe %']}`).join('\n')}

## CRM Health Metrics (HubSpot API)
${JSON.stringify(payload.analysisPayload.crmMetrics, null, 2)}

## Audit Metadata
${JSON.stringify(payload.analysisPayload.metadata, null, 2)}

Provide your complete analysis as JSON.`;

return [{
  json: {
    requestBody: {
      model: "claude-sonnet-4-5-20250929",
      max_tokens: 4096,
      system: systemPrompt,
      messages: [
        { role: "user", content: userMessage }
      ]
    },
    slackChannel: payload.slackChannel
  }
}];

var formatData = $('Format Slack + Report Data').first().json;

var scriptInput = JSON.stringify({
  analysis: formatData.analysis,
  metadata: {
    portalId: formatData.payload && formatData.payload.metadata ? formatData.payload.metadata.portalId : 'N/A',
    tier: formatData.payload && formatData.payload.metadata ? formatData.payload.metadata.tier : 'HubSpot',
    dataSource: formatData.payload && formatData.payload.metadata ? formatData.payload.metadata.dataSource : 'API + CSV'
  }
});

var buffer = Buffer.from(scriptInput, 'utf-8');

return [{
  json: {
    slackMessage: formatData.slackMessage,
    analysis: formatData.analysis,
    payload: formatData.payload
  },
  binary: {
    inputFile: await this.helpers.prepareBinaryData(
      buffer,
      'audit-input.json',
      'application/json'
    )
  }
}];

// ============================================================
// NODE: "Generate Report" — n8n Code Node
// ============================================================
// Mode: Run Once for All Items
// Place AFTER: "Format Slack + Report Data"
// Wire TO: "Send Audit Summary" AND "Upload Report to Slack"
//
// ZERO external modules. Pure string concatenation.
// Generates a styled HTML report uploaded as a file to Slack.
// ============================================================

var formatData = $('Format Slack + Report Data').first().json;
var analysis = formatData.analysis || {};
var payload = formatData.payload || {};
var portalId = (payload.metadata && payload.metadata.portalId) ? payload.metadata.portalId : 'N/A';
var tier = (payload.metadata && payload.metadata.tier) ? payload.metadata.tier : 'HubSpot';
var dataSource = (payload.metadata && payload.metadata.dataSource) ? payload.metadata.dataSource : 'API + CSV';
var dateDisplay = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// ---- Score color helper ----
function sc(score) {
  if (!score) return '#495057';
  if (score.startsWith('A')) return '#00A854';
  if (score.startsWith('B')) return '#2C7BE5';
  if (score.startsWith('C')) return '#F5A623';
  return '#E74C3C';
}

function escHtml(str) {
  if (!str) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ---- Build HTML ----
var h = '';

h += '<!DOCTYPE html>';
h += '<html lang="en"><head><meta charset="UTF-8">';
h += '<meta name="viewport" content="width=device-width, initial-scale=1.0">';
h += '<title>Campaign Audit Report - ' + escHtml(portalId) + '</title>';
h += '<style>';
h += '* { margin: 0; padding: 0; box-sizing: border-box; }';
h += 'body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif; color: #495057; background: #fff; line-height: 1.6; }';
h += '.container { max-width: 800px; margin: 0 auto; padding: 40px; }';
h += '.header { border-bottom: 3px solid #1A3A5C; padding-bottom: 20px; margin-bottom: 30px; }';
h += '.header h1 { font-size: 28px; color: #1A3A5C; margin-bottom: 4px; }';
h += '.header .meta { font-size: 14px; color: #6c757d; }';
h += '.score-card { display: flex; border-radius: 8px; overflow: hidden; margin-bottom: 30px; }';
h += '.score-badge { padding: 24px; min-width: 100px; display: flex; align-items: center; justify-content: center; }';
h += '.score-badge span { font-size: 42px; font-weight: 800; color: #fff; }';
h += '.score-body { background: #E8F4FD; padding: 20px 24px; flex: 1; }';
h += '.score-body h3 { font-size: 16px; color: #1A3A5C; margin-bottom: 6px; }';
h += '.score-body p { font-size: 14px; color: #495057; }';
h += 'h2 { font-size: 20px; color: #1A3A5C; margin: 30px 0 16px; padding-bottom: 8px; border-bottom: 2px solid #E8F4FD; }';
h += 'h2 .rating { font-size: 15px; font-weight: 600; margin-left: 10px; }';
h += 'table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 13px; }';
h += 'th { background: #1A3A5C; color: #fff; text-align: left; padding: 10px 12px; font-weight: 600; }';
h += 'td { padding: 9px 12px; border-bottom: 1px solid #DEE2E6; }';
h += 'tr:nth-child(even) td { background: #F8F9FA; }';
h += '.verdict-good { color: #00A854; font-weight: 700; }';
h += '.verdict-bad { color: #E74C3C; font-weight: 700; }';
h += '.stat-grid { display: flex; gap: 12px; margin-bottom: 20px; }';
h += '.stat-card { flex: 1; padding: 16px; border-radius: 6px; text-align: center; }';
h += '.stat-card .val { font-size: 26px; font-weight: 800; }';
h += '.stat-card .label { font-size: 12px; color: #6c757d; margin-top: 4px; }';
h += '.bullet { padding: 4px 0 4px 20px; font-size: 14px; position: relative; }';
h += '.bullet::before { content: ""; position: absolute; left: 0; top: 12px; width: 8px; height: 8px; border-radius: 50%; }';
h += '.bullet-blue::before { background: #2C7BE5; }';
h += '.bullet-red::before { background: #E74C3C; }';
h += '.bullet-yellow::before { background: #F5A623; }';
h += '.rec-card { display: flex; border-radius: 6px; overflow: hidden; margin-bottom: 16px; }';
h += '.rec-num { min-width: 44px; display: flex; align-items: center; justify-content: center; color: #fff; font-size: 20px; font-weight: 800; }';
h += '.rec-body { background: #F8F9FA; padding: 14px 18px; flex: 1; }';
h += '.rec-body h4 { font-size: 15px; color: #1A3A5C; margin-bottom: 4px; }';
h += '.rec-body .tags { font-size: 12px; margin-bottom: 6px; }';
h += '.rec-body .tags .priority { font-weight: 700; text-transform: uppercase; }';
h += '.rec-body .desc { font-size: 13px; color: #495057; }';
h += '.rec-body .impact { font-size: 13px; color: #2C7BE5; font-style: italic; margin-top: 6px; }';
h += '.warning-bullet { padding: 4px 0 4px 24px; font-size: 14px; }';
h += '.footer { margin-top: 40px; padding-top: 16px; border-top: 1px solid #DEE2E6; font-size: 12px; color: #adb5bd; font-style: italic; }';
h += '@media print { .container { padding: 20px; } .score-card, .stat-grid, .rec-card { break-inside: avoid; } }';
h += '</style></head><body><div class="container">';

// === HEADER ===
h += '<div class="header">';
h += '<h1>Campaign Audit Report</h1>';
h += '<div class="meta">HubSpot Portal ' + escHtml(portalId) + '  |  ' + escHtml(dateDisplay) + '</div>';
h += '</div>';

// === SCORE CARD ===
var score = analysis.overallScore || 'N/A';
var summary = analysis.executiveSummary || 'No summary available.';

h += '<div class="score-card">';
h += '<div class="score-badge" style="background:' + sc(score) + '"><span>' + escHtml(score) + '</span></div>';
h += '<div class="score-body"><h3>Overall Score</h3><p>' + escHtml(summary) + '</p></div>';
h += '</div>';

// === BENCHMARK COMPARISON ===
if (analysis.benchmarkComparison) {
  h += '<h2>Benchmark Comparison</h2>';
  h += '<table><tr><th>Metric</th><th>Yours</th><th>Industry Avg</th><th>Difference</th><th>Verdict</th></tr>';

  var bc = analysis.benchmarkComparison;
  var bcKeys = Object.keys(bc);
  for (var bi = 0; bi < bcKeys.length; bi++) {
    var key = bcKeys[bi];
    var val = bc[key];
    if (!val || typeof val !== 'object') continue;
    var label = key.replace(/([A-Z])/g, ' $1').replace(/^./, function(s) { return s.toUpperCase(); });
    var diff = (val.yours - val.industry).toFixed(1);
    var sign = parseFloat(diff) >= 0 ? '+' : '';
    var isReverseMetric = key === 'bounceRate' || key === 'unsubRate';
    var isGood = isReverseMetric ? val.yours <= val.industry : val.yours >= val.industry;
    var cls = isGood ? 'verdict-good' : 'verdict-bad';

    h += '<tr>';
    h += '<td><strong>' + escHtml(label) + '</strong></td>';
    h += '<td>' + escHtml(String(val.yours)) + '%</td>';
    h += '<td>' + escHtml(String(val.industry)) + '%</td>';
    h += '<td class="' + cls + '">' + sign + diff + '%</td>';
    h += '<td class="' + cls + '">' + (isGood ? 'Above' : 'Below') + '</td>';
    h += '</tr>';
  }
  h += '</table>';
}

// === EMAIL PERFORMANCE ===
if (analysis.emailAnalysis) {
  var ea = analysis.emailAnalysis;
  h += '<h2>Email Performance <span class="rating" style="color:' + sc(ea.overallRating) + '">' + escHtml(ea.overallRating || 'N/A') + '</span></h2>';

  if (ea.emails && ea.emails.length > 0) {
    h += '<table><tr><th>Email</th><th>Score</th><th>Open %</th><th>Click %</th><th>Insight</th></tr>';
    for (var ei = 0; ei < ea.emails.length; ei++) {
      var email = ea.emails[ei];
      var openStr = email.openRate != null ? email.openRate + '%' : '-';
      var clickStr = email.clickRate != null ? email.clickRate + '%' : '-';
      h += '<tr>';
      h += '<td><strong>' + escHtml(email.name || 'Unknown') + '</strong></td>';
      h += '<td style="color:' + sc(email.score) + '; font-weight:700; text-align:center">' + escHtml(email.score || '-') + '</td>';
      h += '<td style="text-align:center">' + escHtml(openStr) + '</td>';
      h += '<td style="text-align:center">' + escHtml(clickStr) + '</td>';
      h += '<td style="font-size:12px">' + escHtml(email.insight || '') + '</td>';
      h += '</tr>';
    }
    h += '</table>';
  }

  if (ea.patterns && ea.patterns.length > 0) {
    h += '<h3 style="font-size:15px; color:#1A3A5C; margin:16px 0 8px">Key Patterns</h3>';
    for (var pi = 0; pi < ea.patterns.length; pi++) {
      h += '<div class="bullet bullet-blue">' + escHtml(ea.patterns[pi]) + '</div>';
    }
  }
}

// === AUDIENCE HEALTH ===
if (analysis.audienceHealth) {
  var ah = analysis.audienceHealth;
  h += '<h2>Audience Health <span class="rating" style="color:' + sc(ah.score) + '">' + escHtml(ah.score || 'N/A') + '</span></h2>';

  var activeRate = ah.activeRate || 0;
  var disengagedRate = ah.disengagedRate || 0;
  var optOutRate = ah.optOutRate || 0;

  h += '<div class="stat-grid">';
  h += '<div class="stat-card" style="background:#E8F4FD"><div class="val" style="color:#1A3A5C">' + escHtml(String(ah.totalContacts || 0)) + '</div><div class="label">Total Contacts</div></div>';
  h += '<div class="stat-card" style="background:#F8F9FA"><div class="val" style="color:' + (activeRate > 30 ? '#00A854' : '#E74C3C') + '">' + activeRate + '%</div><div class="label">Active Rate</div></div>';
  h += '<div class="stat-card" style="background:#E8F4FD"><div class="val" style="color:#495057">' + disengagedRate + '%</div><div class="label">Disengaged</div></div>';
  h += '<div class="stat-card" style="background:#F8F9FA"><div class="val" style="color:#495057">' + optOutRate + '%</div><div class="label">Opted Out</div></div>';
  h += '</div>';

  if (ah.findings && ah.findings.length > 0) {
    h += '<h3 style="font-size:15px; color:#1A3A5C; margin:16px 0 8px">Findings</h3>';
    for (var fi = 0; fi < ah.findings.length; fi++) {
      h += '<div class="bullet bullet-red">' + escHtml(ah.findings[fi]) + '</div>';
    }
  }

  if (ah.risks && ah.risks.length > 0) {
    h += '<h3 style="font-size:15px; color:#E74C3C; margin:16px 0 8px">Risks</h3>';
    for (var ri = 0; ri < ah.risks.length; ri++) {
      h += '<div class="warning-bullet">\u26A0 ' + escHtml(ah.risks[ri]) + '</div>';
    }
  }
}

// === LIFECYCLE FUNNEL ===
if (analysis.funnelAnalysis) {
  var fa = analysis.funnelAnalysis;
  h += '<h2>Lifecycle Funnel <span class="rating" style="color:' + sc(fa.score) + '">' + escHtml(fa.score || 'N/A') + '</span></h2>';

  if (fa.distribution) {
    var distKeys = Object.keys(fa.distribution);
    var total = 0;
    for (var ti = 0; ti < distKeys.length; ti++) {
      total += fa.distribution[distKeys[ti]];
    }

    h += '<table><tr><th>Stage</th><th>Count</th><th>% of Total</th><th style="width:40%">Distribution</th></tr>';
    for (var di = 0; di < distKeys.length; di++) {
      var stage = distKeys[di];
      var count = fa.distribution[stage];
      var pct = total > 0 ? ((count / total) * 100).toFixed(1) : '0.0';
      var barWidth = total > 0 ? Math.round((count / total) * 100) : 0;

      h += '<tr>';
      h += '<td><strong>' + escHtml(stage.charAt(0).toUpperCase() + stage.slice(1)) + '</strong></td>';
      h += '<td style="text-align:center">' + count + '</td>';
      h += '<td style="text-align:center">' + pct + '%</td>';
      h += '<td><div style="background:#E9ECEF; border-radius:4px; height:18px; width:100%"><div style="background:#2C7BE5; border-radius:4px; height:18px; width:' + barWidth + '%"></div></div></td>';
      h += '</tr>';
    }
    h += '</table>';
  }

  if (fa.gaps && fa.gaps.length > 0) {
    h += '<h3 style="font-size:15px; color:#1A3A5C; margin:16px 0 8px">Funnel Gaps</h3>';
    for (var gi = 0; gi < fa.gaps.length; gi++) {
      h += '<div class="bullet bullet-yellow">' + escHtml(fa.gaps[gi]) + '</div>';
    }
  }
}

// === RECOMMENDATIONS ===
if (analysis.recommendations && analysis.recommendations.length > 0) {
  h += '<h2 style="margin-top:40px">Strategic Recommendations</h2>';

  for (var rci = 0; rci < analysis.recommendations.length; rci++) {
    var rec = analysis.recommendations[rci];
    var pColor = rec.priority === 'high' ? '#E74C3C' : rec.priority === 'medium' ? '#F5A623' : '#00A854';
    var effortLabel = rec.effort === 'quick_win' ? 'Quick Win' : rec.effort === 'project' ? 'Project' : (rec.effort || 'Initiative');

    h += '<div class="rec-card">';
    h += '<div class="rec-num" style="background:' + pColor + '">' + (rci + 1) + '</div>';
    h += '<div class="rec-body">';
    h += '<h4>' + escHtml(rec.title || 'Recommendation') + '</h4>';
    h += '<div class="tags"><span class="priority" style="color:' + pColor + '">' + escHtml((rec.priority || '').toUpperCase()) + ' PRIORITY</span> &nbsp;|&nbsp; ' + escHtml(effortLabel) + '</div>';
    if (rec.description) {
      h += '<div class="desc">' + escHtml(rec.description) + '</div>';
    }
    if (rec.expectedImpact) {
      h += '<div class="impact">Expected Impact: ' + escHtml(rec.expectedImpact) + '</div>';
    }
    h += '</div></div>';
  }
}

// === FOOTER ===
h += '<div class="footer">Report generated by Campaign Auditor v1 &nbsp;|&nbsp; Data source: ' + escHtml(dataSource) + ' &nbsp;|&nbsp; ' + escHtml(tier) + '</div>';
h += '</div></body></html>';

// ---- Return as binary file ----
var buffer = Buffer.from(h, 'utf-8');
var dateStr = new Date().toISOString().slice(0, 10);
var filename = 'campaign-audit-' + dateStr + '.html';

return [{
  json: {
    slackMessage: formatData.slackMessage,
    analysis: analysis,
    payload: formatData.payload,
    reportGenerated: true,
    reportFilename: filename,
    reportSize: buffer.length
  },
  binary: {
    report: await this.helpers.prepareBinaryData(
      buffer,
      filename,
      'text/html'
    )
  }
}];

